/* ─── Public Multiples + Comparable Engine ───
 * Powers:
 *   1. Public Comparables table (live Yahoo Finance multiples per ticker)
 *   2. Comparable Engine (private revenue → implied valuation at sector P25/median/P75)
 *
 * Data: data/public_multiples_auto.json
 *   - Generated by scripts/build_public_multiples.py from stocks_raw.json
 *   - Every ticker's fundamentals come from yfinance (Yahoo Finance crumb-auth)
 *   - Sector benchmarks computed as percentiles across each sector's tickers
 *
 * Trust contract:
 *   - Every cell is verifiable on the linked Yahoo Finance ticker page.
 *   - Pre-revenue companies have huge multiples — we surface them with a flag,
 *     not by hiding them.
 *   - The Comparable Engine never estimates private-company revenue. It only
 *     computes implied valuation from the user-supplied revenue.
 */

(function () {
  'use strict';

  const esc = (typeof escapeHtml === 'function')
    ? escapeHtml
    : (s) => String(s == null ? '' : s).replace(/[&<>"']/g, (c) => ({
        '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;'
      }[c]));

  let _data = null;       // full payload from public_multiples_auto.json
  const _state = { search: '', sector: '', sort: 'marketCap' };

  // ── Formatters ─────────────────────────────────────────────────
  function fmtMult(v) {
    if (v == null || !isFinite(v)) return '<span class="pm-na">n/a</span>';
    if (Math.abs(v) >= 1000) return Math.round(v).toLocaleString() + 'x';
    if (Math.abs(v) >= 100) return v.toFixed(0) + 'x';
    if (Math.abs(v) >= 10) return v.toFixed(1) + 'x';
    return v.toFixed(2) + 'x';
  }
  function fmtPct(v) {
    if (v == null || !isFinite(v)) return '<span class="pm-na">n/a</span>';
    const cls = v >= 0 ? 'pm-pos' : 'pm-neg';
    return `<span class="${cls}">${(v * 100).toFixed(1)}%</span>`;
  }
  function fmtCash(n) {
    if (n == null || !isFinite(n) || n === 0) return '<span class="pm-na">n/a</span>';
    if (n >= 1e12) return '$' + (n / 1e12).toFixed(2) + 'T';
    if (n >= 1e9) return '$' + (n / 1e9).toFixed(2) + 'B';
    if (n >= 1e6) return '$' + (n / 1e6).toFixed(0) + 'M';
    return '$' + Math.round(n).toLocaleString();
  }
  function fmtCashPlain(n) {
    if (n == null || !isFinite(n) || n === 0) return 'n/a';
    if (n >= 1e12) return '$' + (n / 1e12).toFixed(2) + 'T';
    if (n >= 1e9) return '$' + (n / 1e9).toFixed(2) + 'B';
    if (n >= 1e6) return '$' + (n / 1e6).toFixed(0) + 'M';
    return '$' + Math.round(n).toLocaleString();
  }

  function isPreRevenue(t) {
    // Heuristic: revenue under $50M typically yields meaningless multiples
    return (t.revenueTTM == null) || t.revenueTTM < 50e6;
  }

  // ── Public Multiples table ─────────────────────────────────────
  function renderPublicMultiplesTable() {
    const body = document.getElementById('pm-body');
    const meta = document.getElementById('pm-meta');
    if (!body || !_data) return;

    let rows = (_data.tickers || []).slice();
    if (_state.sector) rows = rows.filter(t => t.sector === _state.sector);
    if (_state.search) {
      const q = _state.search.toLowerCase();
      rows = rows.filter(t =>
        (t.ticker || '').toLowerCase().includes(q) ||
        (t.company || '').toLowerCase().includes(q)
      );
    }
    rows.sort((a, b) => {
      const av = a[_state.sort];
      const bv = b[_state.sort];
      if (av == null && bv == null) return 0;
      if (av == null) return 1;
      if (bv == null) return -1;
      return bv - av;
    });

    if (rows.length === 0) {
      body.innerHTML = '<tr><td colspan="11" style="text-align:center; padding:30px; color:rgba(255,255,255,0.4);">No tickers match the current filters.</td></tr>';
      return;
    }

    body.innerHTML = rows.map(t => {
      const flag = isPreRevenue(t) ? '<span class="pm-flag-prerev" title="TTM revenue below $50M — multiples are mathematically inflated">pre-rev</span>' : '';
      return `<tr>
        <td><span class="pm-ticker">${esc(t.ticker)}</span></td>
        <td>${esc(t.company || t.ticker)} ${flag}</td>
        <td style="font-size:11.5px; color:rgba(255,255,255,0.6);">${esc(t.sectorLabel || t.sector || '')}</td>
        <td class="pm-num">${esc(t.marketCap || fmtCashPlain(t.marketCapRaw))}</td>
        <td class="pm-num">${fmtMult(t.priceToSalesTTM)}</td>
        <td class="pm-num">${fmtMult(t.enterpriseToRevenue)}</td>
        <td class="pm-num">${fmtMult(t.enterpriseToEbitda)}</td>
        <td class="pm-num">${fmtMult(t.trailingPE)}</td>
        <td class="pm-num">${fmtPct(t.revenueGrowthYoY)}</td>
        <td class="pm-num">${fmtPct(t.grossMarginsTTM)}</td>
        <td><a href="${esc(t.yahooUrl)}" target="_blank" rel="noopener" class="pm-verify-link">Yahoo →</a></td>
      </tr>`;
    }).join('');

    if (meta) {
      const updated = (_data.tickers[0] || {}).lastUpdated || _data.generatedAt || '';
      meta.innerHTML = `<strong>${rows.length}</strong> ticker${rows.length !== 1 ? 's' : ''} · Source: ${esc(_data.source || 'Yahoo Finance')} · Last build: <code>${esc(_data.generatedAt || '')}</code> · Last quote: <code>${esc(updated)}</code>. Pre-rev tickers (TTM revenue &lt; $50M) flagged because their multiples are mathematically meaningless — surface, don't hide.`;
    }
  }

  function bindPublicMultiplesControls() {
    const sectorSel = document.getElementById('pm-sector');
    if (sectorSel && _data) {
      const sectors = Array.from(new Set((_data.tickers || []).map(t => t.sector).filter(Boolean))).sort();
      sectorSel.innerHTML = '<option value="">All sectors</option>' +
        sectors.map(s => {
          const lbl = (_data.sectors.find(x => x.sector === s) || {}).sectorLabel || s;
          return `<option value="${esc(s)}">${esc(lbl)}</option>`;
        }).join('');
      sectorSel.addEventListener('change', (e) => { _state.sector = e.target.value; renderPublicMultiplesTable(); });
    }
    const searchEl = document.getElementById('pm-search');
    if (searchEl) {
      searchEl.addEventListener('input', (e) => { _state.search = e.target.value || ''; renderPublicMultiplesTable(); });
    }
    const sortEl = document.getElementById('pm-sort');
    if (sortEl) {
      sortEl.addEventListener('change', (e) => { _state.sort = e.target.value; renderPublicMultiplesTable(); });
    }
  }

  // ── Comparable Engine ──────────────────────────────────────────
  function renderComparableEngine() {
    const sectorSel = document.getElementById('ce-sector');
    const revInput = document.getElementById('ce-revenue');
    const unitSel = document.getElementById('ce-revenue-unit');
    const out = document.getElementById('ce-output-card');
    if (!sectorSel || !out || !_data) return;

    // Populate sector dropdown — only sectors with >=2 tickers AND meaningful multiples
    const usable = (_data.sectors || []).filter(s => s.priceToSales && s.priceToSales.median != null);
    sectorSel.innerHTML = '<option value="">— Pick a sector —</option>' +
      usable.map(s => `<option value="${esc(s.sector)}">${esc(s.sectorLabel)} (n=${s.n})</option>`).join('');

    function compute() {
      const sectorKey = sectorSel.value;
      const rev = parseFloat(revInput.value || '0');
      const unit = parseFloat(unitSel.value || '1000000');
      if (!sectorKey) {
        out.innerHTML = '<div class="ce-empty">Pick a sector and enter revenue to compute the implied valuation range.</div>';
        return;
      }
      if (!rev || rev <= 0) {
        out.innerHTML = '<div class="ce-empty">Enter the private company\'s TTM revenue to compute implied valuation.</div>';
        return;
      }
      const sector = (_data.sectors || []).find(s => s.sector === sectorKey);
      if (!sector) {
        out.innerHTML = '<div class="ce-empty">Sector data unavailable.</div>';
        return;
      }
      const revUSD = rev * unit;
      const ps = sector.priceToSales || {};
      const evr = sector.evRevenue || {};

      // Implied valuation = revenue × multiple
      const valMedian = ps.median != null ? revUSD * ps.median : null;
      const valP25 = ps.p25 != null ? revUSD * ps.p25 : null;
      const valP75 = ps.p75 != null ? revUSD * ps.p75 : null;

      // List the comp set tickers used
      const comps = (_data.tickers || [])
        .filter(t => t.sector === sectorKey && t.priceToSalesTTM != null)
        .sort((a, b) => (b.priceToSalesTTM || 0) - (a.priceToSalesTTM || 0));

      const compRows = comps.map(t => `<div class="ce-comp-row">
        <span class="ce-comp-name"><strong>${esc(t.ticker)}</strong> · ${esc(t.company || '')}</span>
        <span class="ce-comp-mult">P/S ${fmtMult(t.priceToSalesTTM)}</span>
        <a href="${esc(t.yahooUrl)}" target="_blank" rel="noopener" class="ce-comp-link">Verify →</a>
      </div>`).join('');

      // Detect pre-revenue distortion
      const allPreRev = comps.every(c => isPreRevenue(c));
      const preRevWarn = allPreRev
        ? '<div class="ce-disclaimer"><strong style="color:#f59e0b;">⚠ Sector caution:</strong> Every comparable in this sector is pre-revenue (TTM revenue &lt; $50M), so the implied multiples reflect speculative future expectations rather than current operating economics. Results below should be read directionally, not as a fair-value estimate.</div>'
        : '';

      out.innerHTML = `<div class="ce-result-grid">
          <div class="ce-result-card">
            <div class="ce-result-lbl">P25 (low)</div>
            <div class="ce-result-val">${valP25 != null ? fmtCashPlain(valP25) : 'n/a'}</div>
            <div class="ce-result-mult">${ps.p25 != null ? ps.p25.toFixed(2) + 'x P/S' : ''}</div>
          </div>
          <div class="ce-result-card ce-median">
            <div class="ce-result-lbl">Median</div>
            <div class="ce-result-val">${valMedian != null ? fmtCashPlain(valMedian) : 'n/a'}</div>
            <div class="ce-result-mult">${ps.median != null ? ps.median.toFixed(2) + 'x P/S' : ''}</div>
          </div>
          <div class="ce-result-card">
            <div class="ce-result-lbl">P75 (high)</div>
            <div class="ce-result-val">${valP75 != null ? fmtCashPlain(valP75) : 'n/a'}</div>
            <div class="ce-result-mult">${ps.p75 != null ? ps.p75.toFixed(2) + 'x P/S' : ''}</div>
          </div>
        </div>
        ${preRevWarn}
        <div class="ce-disclaimer" style="background:rgba(96,165,250,0.06); border-left-color:rgba(96,165,250,0.5);">
          <strong style="color:#60a5fa;">Method:</strong> Implied valuation = your revenue ($${rev.toLocaleString()} ${unitSel.options[unitSel.selectedIndex].text}) × sector public-comp P/S multiple. EV/Revenue median for ${esc(sector.sectorLabel)} is ${fmtMult(evr.median)}.
        </div>
        <div class="ce-comp-list">
          <div class="ce-comp-title">Comp set used (${comps.length} live public tickers, sorted by P/S desc)</div>
          ${compRows || '<div class="ce-empty">No tickers with P/S data in this sector.</div>'}
        </div>`;
    }

    sectorSel.addEventListener('change', compute);
    revInput.addEventListener('input', compute);
    unitSel.addEventListener('change', compute);
  }

  // ── Round-by-Round Comp Engine ─────────────────────────────────
  // Combines FUNDING_TRACKER (latest round per company) + DEAL_TRACKER
  // (per-deal entries). Builds a sector-aware comp browser.
  const _rcState = { sector: '', stage: '', search: '' };

  // Parse "$XB" / "$XM" / "$X.X" amounts → USD number (or null)
  function parseAmount(s) {
    if (!s) return null;
    var m = String(s).match(/\$?\s*([\d,]+(?:\.\d+)?)\s*([KMBT]\+?)?/i);
    if (!m) return null;
    var n = parseFloat(m[1].replace(/,/g, ''));
    var unit = (m[2] || '').toUpperCase().replace('+','');
    if (unit === 'K') n *= 1e3;
    else if (unit === 'M') n *= 1e6;
    else if (unit === 'B') n *= 1e9;
    else if (unit === 'T') n *= 1e12;
    return isFinite(n) ? n : null;
  }

  // Map a company name to its sector via the COMPANIES global
  function sectorFor(companyName) {
    if (typeof COMPANIES === 'undefined' || !Array.isArray(COMPANIES)) return null;
    var c = COMPANIES.find(function (x) { return x.name === companyName; });
    return c ? c.sector : null;
  }

  // Build the unified deal list (one row per round we know about)
  function buildRoundList() {
    var rows = [];
    var seen = new Set(); // dedupe by company+stage+date
    function dedupKey(r) { return (r.company || '') + '|' + (r.stage || '') + '|' + (r.date || ''); }

    // FUNDING_TRACKER → latest round per company
    if (typeof FUNDING_TRACKER !== 'undefined' && Array.isArray(FUNDING_TRACKER)) {
      FUNDING_TRACKER.forEach(function (f) {
        var row = {
          company: f.company,
          stage: f.lastRound || '',
          amount: f.lastRoundAmount || '',
          amountUSD: parseAmount(f.lastRoundAmount),
          valuation: f.valuation || '',
          valuationUSD: parseAmount(f.valuation),
          leadInvestor: (Array.isArray(f.leadInvestors) ? f.leadInvestors.filter(function (x) { return x && x !== 'Undisclosed'; }).slice(0, 2).join(', ') : '') || (Array.isArray(f.leadInvestors) ? f.leadInvestors[0] : ''),
          date: f.lastRoundDate || '',
          sector: sectorFor(f.company),
          source: 'FUNDING_TRACKER'
        };
        var k = dedupKey(row);
        if (!seen.has(k)) { rows.push(row); seen.add(k); }
      });
    }

    // DEAL_TRACKER → per-deal entries (may include older rounds)
    if (typeof DEAL_TRACKER !== 'undefined' && Array.isArray(DEAL_TRACKER)) {
      DEAL_TRACKER.forEach(function (d) {
        var row = {
          company: d.company,
          stage: d.round || '',
          amount: d.amount || '',
          amountUSD: parseAmount(d.amount),
          valuation: d.valuation || '',
          valuationUSD: parseAmount(d.valuation),
          leadInvestor: (d.investor && d.investor !== 'Undisclosed') ? d.investor : '',
          date: d.date || '',
          sector: sectorFor(d.company),
          source: 'DEAL_TRACKER'
        };
        var k = dedupKey(row);
        if (!seen.has(k)) { rows.push(row); seen.add(k); }
      });
    }

    return rows.filter(function (r) { return r.amountUSD && r.amountUSD > 0; });
  }

  function median(arr) {
    if (!arr.length) return null;
    var s = arr.slice().sort(function (a, b) { return a - b; });
    var m = Math.floor(s.length / 2);
    return s.length % 2 ? s[m] : (s[m - 1] + s[m]) / 2;
  }

  function renderRoundCompTable(allRows) {
    var body = document.getElementById('rc-body');
    var summary = document.getElementById('rc-summary');
    if (!body) return;

    var rows = allRows.slice();
    if (_rcState.sector) rows = rows.filter(function (r) { return r.sector === _rcState.sector; });
    if (_rcState.stage) rows = rows.filter(function (r) { return (r.stage || '').toLowerCase() === _rcState.stage.toLowerCase(); });
    if (_rcState.search) {
      var q = _rcState.search.toLowerCase();
      rows = rows.filter(function (r) {
        return (r.company || '').toLowerCase().includes(q) ||
               (r.leadInvestor || '').toLowerCase().includes(q);
      });
    }
    rows.sort(function (a, b) {
      // Sort by date desc, then amount desc
      if ((b.date || '') !== (a.date || '')) return (b.date || '').localeCompare(a.date || '');
      return (b.amountUSD || 0) - (a.amountUSD || 0);
    });

    if (rows.length === 0) {
      body.innerHTML = '<tr><td colspan="7" class="rc-no-data">No comparable rounds match these filters. Try widening sector or stage.</td></tr>';
      if (summary) summary.innerHTML = '';
      return;
    }

    body.innerHTML = rows.slice(0, 200).map(function (r) {
      var valCell = r.valuation ? esc(r.valuation) : '<span class="pm-na">not disclosed</span>';
      var leadCell = r.leadInvestor ? esc(r.leadInvestor) : '<span class="pm-na">not disclosed</span>';
      var sectorCell = r.sector ? '<span style="font-size:11.5px; color:rgba(255,255,255,0.6);">' + esc(r.sector) + '</span>' : '<span class="pm-na">unknown</span>';
      var dateCell = r.date ? esc(r.date) : '<span class="pm-na">—</span>';
      var compLink = '<a href="company.html?name=' + encodeURIComponent(r.company) + '" style="color:#a855f7; text-decoration:none;">' + esc(r.company) + '</a>';
      return '<tr>' +
        '<td>' + compLink + '</td>' +
        '<td>' + sectorCell + '</td>' +
        '<td><span class="brief-badge brief-badge-round" style="background:rgba(168,85,247,0.15); color:#c084fc; padding:2px 8px; border-radius:10px; font-size:11px;">' + esc(r.stage || '—') + '</span></td>' +
        '<td class="pm-num">' + esc(r.amount || '') + '</td>' +
        '<td class="pm-num">' + valCell + '</td>' +
        '<td>' + leadCell + '</td>' +
        '<td>' + dateCell + '</td>' +
      '</tr>';
    }).join('');

    if (summary) {
      var amounts = rows.map(function (r) { return r.amountUSD; }).filter(function (n) { return n; });
      var vals = rows.map(function (r) { return r.valuationUSD; }).filter(function (n) { return n; });
      var med = median(amounts);
      var medVal = median(vals);
      summary.innerHTML =
        '<div class="rc-summary-card"><div class="rc-summary-lbl">Comp set size</div><div class="rc-summary-val">' + rows.length + '</div></div>' +
        '<div class="rc-summary-card"><div class="rc-summary-lbl">Median round</div><div class="rc-summary-val">' + (med ? fmtCashPlain(med) : 'n/a') + '</div></div>' +
        '<div class="rc-summary-card"><div class="rc-summary-lbl">Median valuation</div><div class="rc-summary-val">' + (medVal ? fmtCashPlain(medVal) : '<span style="font-size:13px; color:rgba(255,255,255,0.5);">no disclosed</span>') + '</div></div>' +
        '<div class="rc-summary-card"><div class="rc-summary-lbl">With disclosed valuation</div><div class="rc-summary-val">' + vals.length + '/' + rows.length + '</div></div>';
    }
  }

  function initRoundComp() {
    var rows = buildRoundList();
    if (rows.length === 0) {
      var body = document.getElementById('rc-body');
      if (body) body.innerHTML = '<tr><td colspan="7" class="rc-no-data">Funding tracker data unavailable.</td></tr>';
      return;
    }

    // Populate sector dropdown
    var sectorSel = document.getElementById('rc-sector');
    if (sectorSel) {
      var sectors = Array.from(new Set(rows.map(function (r) { return r.sector; }).filter(Boolean))).sort();
      sectorSel.innerHTML = '<option value="">All sectors (' + rows.length + ' rounds)</option>' +
        sectors.map(function (s) {
          var n = rows.filter(function (r) { return r.sector === s; }).length;
          return '<option value="' + esc(s) + '">' + esc(s) + ' (' + n + ')</option>';
        }).join('');
      sectorSel.addEventListener('change', function (e) { _rcState.sector = e.target.value; renderRoundCompTable(rows); });
    }

    // Populate stage dropdown
    var stageSel = document.getElementById('rc-stage');
    if (stageSel) {
      var stages = Array.from(new Set(rows.map(function (r) { return r.stage; }).filter(Boolean))).sort();
      stageSel.innerHTML = '<option value="">All stages</option>' +
        stages.map(function (s) {
          var n = rows.filter(function (r) { return r.stage === s; }).length;
          return '<option value="' + esc(s) + '">' + esc(s) + ' (' + n + ')</option>';
        }).join('');
      stageSel.addEventListener('change', function (e) { _rcState.stage = e.target.value; renderRoundCompTable(rows); });
    }

    var searchEl = document.getElementById('rc-search');
    if (searchEl) {
      searchEl.addEventListener('input', function (e) { _rcState.search = e.target.value || ''; renderRoundCompTable(rows); });
    }

    renderRoundCompTable(rows);
  }

  // ── Bootstrap ──────────────────────────────────────────────────
  function init() {
    // Round comp engine reads global FUNDING_TRACKER + DEAL_TRACKER (in data.js,
    // already loaded before this script). It doesn't need the multiples fetch.
    initRoundComp();

    fetch('data/public_multiples_auto.json?v=' + Date.now())
      .then(r => r.ok ? r.json() : Promise.reject('fetch failed'))
      .then(d => {
        _data = d;
        bindPublicMultiplesControls();
        renderPublicMultiplesTable();
        renderComparableEngine();
      })
      .catch((err) => {
        console.error('[valuations-multiples] failed to load:', err);
        const body = document.getElementById('pm-body');
        if (body) body.innerHTML = '<tr><td colspan="11" style="text-align:center; padding:40px; color:rgba(255,255,255,0.5);">Public multiples data unavailable.</td></tr>';
      });
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }
})();
